'use client';
import { useEffect, useState, useCallback } from 'react';

interface Message {
  id: string; name: string; email: string; phone?: string;
  subject?: string; message: string; isRead: boolean; createdAt: string;
}

export default function AdminMessagesPage() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [selected, setSelected] = useState<Message | null>(null);
  const [loading, setLoading] = useState(true);
  const [unread, setUnread] = useState(false);

  const fetch_messages = useCallback(async () => {
    setLoading(true);
    const token = localStorage.getItem('goc_access_token');
    const API = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000/api';
    const params = unread ? '?unread=true' : '';
    const res = await fetch(`${API}/contact${params}`, { headers: { Authorization: `Bearer ${token}` } });
    const data = await res.json();
    setMessages(data.messages || []);
    setLoading(false);
  }, [unread]);

  useEffect(() => { fetch_messages(); }, [fetch_messages]);

  const markRead = async (id: string) => {
    const token = localStorage.getItem('goc_access_token');
    const API = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000/api';
    await fetch(`${API}/contact/${id}/read`, { method: 'PATCH', headers: { Authorization: `Bearer ${token}` } });
    setMessages(ms => ms.map(m => m.id === id ? { ...m, isRead: true } : m));
    if (selected?.id === id) setSelected(s => s ? { ...s, isRead: true } : null);
  };

  const deleteMsg = async (id: string) => {
    if (!confirm('Delete this message?')) return;
    const token = localStorage.getItem('goc_access_token');
    const API = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000/api';
    await fetch(`${API}/contact/${id}`, { method: 'DELETE', headers: { Authorization: `Bearer ${token}` } });
    setMessages(ms => ms.filter(m => m.id !== id));
    if (selected?.id === id) setSelected(null);
  };

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem', flexWrap: 'wrap', gap: '1rem' }}>
        <h1 style={{ fontFamily: 'var(--font-display)', fontSize: '2rem', fontWeight: 700 }}>Messages</h1>
        <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.85rem', color: 'var(--cream-dim)', cursor: 'pointer' }}>
          <input type="checkbox" checked={unread} onChange={e => setUnread(e.target.checked)} style={{ accentColor: 'var(--gold)' }} />
          Show unread only
        </label>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: selected ? '1fr 1.5fr' : '1fr', gap: '1.5rem' }}>
        {/* List */}
        <div className="glass" style={{ borderRadius: '16px', overflow: 'hidden', height: 'fit-content' }}>
          {loading ? <div style={{ padding: '2rem', textAlign: 'center', color: 'var(--cream-dim)' }}>Loading...</div> :
            messages.length === 0 ? <div style={{ padding: '2rem', textAlign: 'center', color: 'var(--cream-dim)' }}>No messages found.</div> :
              messages.map(m => (
                <div key={m.id} onClick={() => { setSelected(m); if (!m.isRead) markRead(m.id); }}
                  style={{ padding: '1.25rem', borderBottom: '1px solid rgba(255,255,255,0.05)', cursor: 'pointer', background: selected?.id === m.id ? 'rgba(212,175,55,0.07)' : m.isRead ? 'transparent' : 'rgba(107,63,160,0.06)', transition: 'background 0.2s' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '0.25rem' }}>
                    <span style={{ fontWeight: m.isRead ? 400 : 700, color: 'var(--cream)', fontSize: '0.9rem' }}>{m.name}</span>
                    {!m.isRead && <span style={{ width: 8, height: 8, borderRadius: '50%', background: '#7B5EA7', display: 'inline-block' }} />}
                  </div>
                  <div style={{ fontSize: '0.8rem', color: 'var(--gold)', marginBottom: '0.25rem' }}>{m.subject || '(No subject)'}</div>
                  <div style={{ fontSize: '0.78rem', color: 'var(--cream-dim)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{m.message}</div>
                  <div style={{ fontSize: '0.72rem', color: 'rgba(200,196,188,0.4)', marginTop: '0.4rem' }}>{new Date(m.createdAt).toLocaleDateString('en-IN')}</div>
                </div>
              ))
          }
        </div>

        {/* Detail */}
        {selected && (
          <div className="glass" style={{ borderRadius: '16px', padding: '2rem' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1.5rem' }}>
              <div>
                <h2 style={{ fontFamily: 'var(--font-display)', fontSize: '1.4rem', fontWeight: 700, marginBottom: '0.25rem' }}>{selected.subject || '(No subject)'}</h2>
                <p style={{ fontSize: '0.82rem', color: 'var(--cream-dim)', margin: 0 }}>From: <strong style={{ color: 'var(--cream)' }}>{selected.name}</strong> · {selected.email}{selected.phone ? ` · ${selected.phone}` : ''}</p>
              </div>
              <button id={`delete-msg-${selected.id}`} onClick={() => deleteMsg(selected.id)} style={{ background: 'none', border: 'none', color: '#f87171', cursor: 'pointer', fontSize: '1.2rem' }}>🗑</button>
            </div>
            <div style={{ borderTop: '1px solid rgba(255,255,255,0.06)', paddingTop: '1.5rem', color: 'var(--cream-dim)', lineHeight: 1.8, fontSize: '0.9rem', whiteSpace: 'pre-wrap' }}>{selected.message}</div>
            <a href={`mailto:${selected.email}?subject=Re: ${selected.subject || 'Your message to Grace of Christ'}`}
              className="btn btn-gold" style={{ marginTop: '1.5rem', display: 'inline-flex' }}>✉ Reply by Email</a>
          </div>
        )}
      </div>
    </div>
  );
}

'use client';
import { useEffect, useState } from 'react';

export default function AdminReportsPage() {
  const API = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000/api';
  const [from, setFrom] = useState('');
  const [to, setTo] = useState('');
  const [stats, setStats] = useState<any>(null);

  useEffect(() => {
    const token = localStorage.getItem('goc_access_token');
    fetch(`${API}/reports/summary`, { headers: { Authorization: `Bearer ${token}` } })
      .then(r => r.json()).then(setStats).catch(console.error);
  }, []);

  const downloadCSV = () => {
    const token = localStorage.getItem('goc_access_token');
    const params = new URLSearchParams({ ...(from && { from }), ...(to && { to }) });
    const url = `${API}/reports/donations/csv?${params}`;
    // Trigger download with auth (fetch + blob)
    fetch(url, { headers: { Authorization: `Bearer ${token}` } })
      .then(r => r.blob())
      .then(blob => {
        const a = document.createElement('a');
        a.href = URL.createObjectURL(blob);
        a.download = `GOC_Donations_${new Date().toISOString().split('T')[0]}.csv`;
        a.click();
      });
  };

  return (
    <div>
      <h1 style={{ fontFamily: 'var(--font-display)', fontSize: '2rem', fontWeight: 700, marginBottom: '0.5rem' }}>Reports</h1>
      <p style={{ color: 'var(--cream-dim)', fontSize: '0.88rem', marginBottom: '2.5rem' }}>Export donation data and review ministry statistics.</p>

      {/* Summary */}
      {stats && (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '1.25rem', marginBottom: '2.5rem' }}>
          {[
            { label: 'Total Donations', value: stats.totalDonations, icon: '💰', color: 'var(--gold)' },
            { label: 'Total Revenue', value: `₹${Number(stats.totalRevenue).toLocaleString('en-IN')}`, icon: '💵', color: '#4ade80' },
            { label: 'Events', value: stats.totalEvents, icon: '📅', color: '#60a5fa' },
            { label: 'Sermons', value: stats.totalSermons, icon: '🎙', color: '#c084fc' },
          ].map(s => (
            <div key={s.label} className="glass" style={{ padding: '1.5rem', borderRadius: '14px', borderLeft: `4px solid ${s.color}` }}>
              <div style={{ fontSize: '1.5rem', marginBottom: '0.5rem' }}>{s.icon}</div>
              <div style={{ fontFamily: 'var(--font-display)', fontSize: '2rem', fontWeight: 700, color: s.color }}>{s.value}</div>
              <div style={{ fontSize: '0.75rem', color: 'var(--cream-dim)', textTransform: 'uppercase', letterSpacing: '0.06em', marginTop: '0.25rem' }}>{s.label}</div>
            </div>
          ))}
        </div>
      )}

      {/* CSV Export */}
      <div className="glass" style={{ padding: '2rem', borderRadius: '16px' }}>
        <h2 style={{ fontFamily: 'var(--font-display)', fontSize: '1.4rem', fontWeight: 700, marginBottom: '1.5rem' }}>Export Donation Report (CSV)</h2>
        <div style={{ display: 'flex', gap: '1rem', flexWrap: 'wrap', alignItems: 'flex-end' }}>
          <div>
            <label style={{ fontSize: '0.78rem', color: 'var(--cream-dim)', display: 'block', marginBottom: '0.4rem' }}>From Date</label>
            <input id="report-from" type="date" className="input-field" value={from} onChange={e => setFrom(e.target.value)} style={{ width: '180px' }} />
          </div>
          <div>
            <label style={{ fontSize: '0.78rem', color: 'var(--cream-dim)', display: 'block', marginBottom: '0.4rem' }}>To Date</label>
            <input id="report-to" type="date" className="input-field" value={to} onChange={e => setTo(e.target.value)} style={{ width: '180px' }} />
          </div>
          <button id="export-csv-btn" className="btn btn-gold" onClick={downloadCSV}>⬇ Download CSV</button>
        </div>
        <p style={{ fontSize: '0.78rem', color: 'var(--cream-dim)', marginTop: '1rem', opacity: 0.7 }}>
          Leave dates empty to export all donations. CSV includes: Receipt ID, Donor, Email, Phone, Amount, Method, Date.
        </p>
      </div>
    </div>
  );
}

'use client';
import { useEffect, useState, useCallback } from 'react';

interface Sermon {
  id: string; title: string; description?: string; videoUrl: string;
  speaker: string; date: string; tags: string[]; isPublished: boolean;
}

const EMPTY: Omit<Sermon, 'id'> = { title: '', description: '', videoUrl: '', speaker: 'Pastor K. John Prasad', date: '', tags: [], isPublished: true };

export default function AdminSermonsPage() {
  const [sermons, setSermons] = useState<Sermon[]>([]);
  const [form, setForm] = useState<Omit<Sermon, 'id'>>(EMPTY);
  const [tagsInput, setTagsInput] = useState('');
  const [editId, setEditId] = useState<string | null>(null);
  const [showForm, setShowForm] = useState(false);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');

  const API = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000/api';
  const token = () => localStorage.getItem('goc_access_token');

  const fetchSermons = useCallback(async () => {
    setLoading(true);
    const res = await fetch(`${API}/sermons?limit=50`, { headers: { Authorization: `Bearer ${token()}` } });
    const data = await res.json();
    setSermons(data.sermons || []);
    setLoading(false);
  }, []);

  useEffect(() => { fetchSermons(); }, [fetchSermons]);

  const openCreate = () => { setForm(EMPTY); setTagsInput(''); setEditId(null); setShowForm(true); setError(''); };
  const openEdit = (s: Sermon) => { setForm({ title: s.title, description: s.description, videoUrl: s.videoUrl, speaker: s.speaker, date: s.date.split('T')[0], tags: s.tags, isPublished: s.isPublished }); setTagsInput(s.tags.join(', ')); setEditId(s.id); setShowForm(true); setError(''); };

  const handleSave = async () => {
    setSaving(true); setError('');
    try {
      const body = { ...form, date: new Date(form.date).toISOString(), tags: tagsInput.split(',').map(t => t.trim()).filter(Boolean) };
      const url = editId ? `${API}/sermons/${editId}` : `${API}/sermons`;
      const method = editId ? 'PUT' : 'POST';
      const res = await fetch(url, { method, headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token()}` }, body: JSON.stringify(body) });
      if (!res.ok) throw new Error('Save failed');
      setShowForm(false); fetchSermons();
    } catch { setError('Failed to save sermon.'); }
    setSaving(false);
  };

  const deleteSermon = async (id: string) => {
    if (!confirm('Delete this sermon?')) return;
    await fetch(`${API}/sermons/${id}`, { method: 'DELETE', headers: { Authorization: `Bearer ${token()}` } });
    fetchSermons();
  };

  const F = (k: keyof typeof form, v: any) => setForm(f => ({ ...f, [k]: v }));

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
        <h1 style={{ fontFamily: 'var(--font-display)', fontSize: '2rem', fontWeight: 700 }}>Sermons</h1>
        <button id="create-sermon-btn" className="btn btn-gold" onClick={openCreate}>+ Add Sermon</button>
      </div>

      {showForm && (
        <div className="glass" style={{ padding: '2rem', borderRadius: '16px', marginBottom: '2rem' }}>
          <h2 style={{ fontFamily: 'var(--font-display)', fontSize: '1.4rem', fontWeight: 700, marginBottom: '1.5rem' }}>{editId ? 'Edit Sermon' : 'Add Sermon'}</h2>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '1rem' }}>
            <div><label style={{ fontSize: '0.78rem', color: 'var(--cream-dim)', display: 'block', marginBottom: '0.4rem' }}>Title *</label><input id="sermon-title" className="input-field" value={form.title} onChange={e => F('title', e.target.value)} /></div>
            <div><label style={{ fontSize: '0.78rem', color: 'var(--cream-dim)', display: 'block', marginBottom: '0.4rem' }}>Speaker *</label><input id="sermon-speaker" className="input-field" value={form.speaker} onChange={e => F('speaker', e.target.value)} /></div>
            <div><label style={{ fontSize: '0.78rem', color: 'var(--cream-dim)', display: 'block', marginBottom: '0.4rem' }}>Date *</label><input id="sermon-date" type="date" className="input-field" value={form.date} onChange={e => F('date', e.target.value)} /></div>
            <div><label style={{ fontSize: '0.78rem', color: 'var(--cream-dim)', display: 'block', marginBottom: '0.4rem' }}>YouTube URL *</label><input id="sermon-video-url" className="input-field" placeholder="https://youtube.com/watch?v=..." value={form.videoUrl} onChange={e => F('videoUrl', e.target.value)} /></div>
          </div>
          <div style={{ marginTop: '1rem' }}>
            <label style={{ fontSize: '0.78rem', color: 'var(--cream-dim)', display: 'block', marginBottom: '0.4rem' }}>Description</label>
            <textarea id="sermon-description" className="input-field" rows={2} value={form.description} onChange={e => F('description', e.target.value)} style={{ resize: 'vertical' }} />
          </div>
          <div style={{ marginTop: '1rem' }}>
            <label style={{ fontSize: '0.78rem', color: 'var(--cream-dim)', display: 'block', marginBottom: '0.4rem' }}>Tags (comma separated)</label>
            <input id="sermon-tags" className="input-field" placeholder="Grace, Faith, Prayer" value={tagsInput} onChange={e => setTagsInput(e.target.value)} />
          </div>
          <div style={{ marginTop: '1rem', display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
            <input id="sermon-published" type="checkbox" checked={form.isPublished} onChange={e => F('isPublished', e.target.checked)} style={{ accentColor: 'var(--gold)' }} />
            <label htmlFor="sermon-published" style={{ fontSize: '0.85rem', color: 'var(--cream-dim)' }}>Published</label>
          </div>
          {error && <p style={{ color: '#f87171', fontSize: '0.82rem', marginTop: '0.75rem' }}>{error}</p>}
          <div style={{ display: 'flex', gap: '1rem', marginTop: '1.5rem' }}>
            <button id="save-sermon-btn" className="btn btn-gold" onClick={handleSave} disabled={saving}>{saving ? 'Saving...' : 'Save Sermon'}</button>
            <button className="btn btn-glass" onClick={() => setShowForm(false)}>Cancel</button>
          </div>
        </div>
      )}

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '1.25rem' }}>
        {loading ? <p style={{ color: 'var(--cream-dim)' }}>Loading...</p>
          : sermons.map(s => (
            <div key={s.id} className="glass" style={{ borderRadius: '14px', overflow: 'hidden' }}>
              <img src={`https://img.youtube.com/vi/${s.videoUrl.split('v=')[1]?.split('&')[0] || ''}/mqdefault.jpg`} alt={s.title} style={{ width: '100%', height: '160px', objectFit: 'cover', opacity: 0.8 }} />
              <div style={{ padding: '1.25rem' }}>
                <div style={{ fontWeight: 600, color: 'var(--cream)', marginBottom: '0.25rem', fontSize: '0.92rem' }}>{s.title}</div>
                <div style={{ fontSize: '0.78rem', color: 'var(--cream-dim)', marginBottom: '1rem' }}>{s.speaker} · {new Date(s.date).toLocaleDateString('en-IN')}</div>
                <div style={{ display: 'flex', gap: '0.5rem' }}>
                  <button id={`edit-sermon-${s.id}`} className="btn btn-glass" onClick={() => openEdit(s)} style={{ padding: '0.3rem 0.75rem', fontSize: '0.75rem', flex: 1 }}>✏ Edit</button>
                  <button id={`delete-sermon-${s.id}`} onClick={() => deleteSermon(s.id)} style={{ padding: '0.3rem 0.75rem', background: 'none', border: '1px solid rgba(239,68,68,0.3)', color: '#f87171', borderRadius: '6px', cursor: 'pointer', fontSize: '0.75rem' }}>🗑</button>
                </div>
              </div>
            </div>
          ))}
      </div>
    </div>
  );
}

'use client';
import { useState } from 'react';
import Navbar from '@/components/Navbar';
import Footer from '@/components/Footer';
import { useRouter } from 'next/navigation';

const paymentMethods = [
  { id: 'upi', label: 'UPI', icon: '📱' },
  { id: 'card', label: 'Credit / Debit Card', icon: '💳' },
  { id: 'netbanking', label: 'Net Banking', icon: '🏦' },
  { id: 'wallet', label: 'Wallet', icon: '👛' },
  { id: 'cash', label: 'Cash / Hand', icon: '💵' },
];

const presetAmounts = [101, 501, 1001, 2001, 5001, 11001];

type Step = 1 | 2 | 3;

export default function DonatePage() {
  const router = useRouter();
  const [step, setStep] = useState<Step>(1);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const [form, setForm] = useState({
    donorName: '', email: '', phone: '',
    amount: 501, customAmount: '',
    paymentMethod: 'upi',
    notes: '',
  });

  const setField = (k: keyof typeof form, v: any) => setForm(f => ({ ...f, [k]: v }));

  const finalAmount = form.customAmount ? parseFloat(form.customAmount) : form.amount;

  // Step 1 → 2 validation
  const goToStep2 = () => {
    if (!form.donorName.trim() || !form.email.trim() || !form.phone.trim()) {
      setError('Please fill all required fields.'); return;
    }
    setError(''); setStep(2);
  };

  // Submit donation (mock payment)
  const handleDonate = async () => {
    if (!finalAmount || finalAmount < 1) { setError('Please enter a valid amount.'); return; }
    setLoading(true); setError('');
    try {
      const API = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000/api';

      // Create mock order
      const orderRes = await fetch(`${API}/donations/order`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ amount: finalAmount }),
      });
      if (!orderRes.ok) throw new Error('Order creation failed');

      // Submit donation with mockConfirm: true (dev mode)
      const donateRes = await fetch(`${API}/donations`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          donorName: form.donorName,
          email: form.email,
          phone: form.phone,
          amount: finalAmount,
          paymentMethod: form.paymentMethod,
          notes: form.notes,
          mockConfirm: true,
        }),
      });

      const data = await donateRes.json();
      if (!donateRes.ok) throw new Error(data.error || 'Donation failed');

      router.push(`/donate/receipt/${data.receiptId}`);
    } catch (err: any) {
      setError(err.message || 'Something went wrong. Please try again.');
      setLoading(false);
    }
  };

  return (
    <>
      <Navbar />

      {/* Header */}
      <section className="gradient-hero" style={{ paddingTop: '140px', paddingBottom: '4rem', textAlign: 'center' }}>
        <div className="container">
          <div className="section-label" style={{ justifyContent: 'center' }}>Support GOC</div>
          <h1 style={{ fontFamily: 'var(--font-display)', fontSize: 'clamp(2.5rem, 5vw, 4rem)', fontWeight: 700, marginBottom: '1rem' }}>
            Make a <span className="text-gradient-gold">Donation</span>
          </h1>
          <p style={{ color: 'var(--cream-dim)', maxWidth: '540px', margin: '0 auto', lineHeight: 1.8 }}>
            Every gift, large or small, advances the Kingdom of God and supports ministry in Kakinada.
          </p>
        </div>
      </section>

      <section className="section" style={{ background: 'var(--midnight)' }}>
        <div className="container" style={{ maxWidth: '700px' }}>

          {/* Step Indicator */}
          <div style={{ display: 'flex', alignItems: 'center', marginBottom: '3rem', gap: '0' }}>
            {(['Your Details', 'Amount & Payment', 'Confirm'][0]).split('').length > 0 && [1, 2, 3].map((s, i) => (
              <div key={s} style={{ display: 'flex', alignItems: 'center', flex: i < 2 ? 1 : 'none' }}>
                <div style={{
                  width: 36, height: 36, borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center',
                  background: step >= s ? 'linear-gradient(135deg, var(--gold), var(--gold-light))' : 'rgba(255,255,255,0.05)',
                  color: step >= s ? '#070B14' : 'var(--cream-dim)',
                  fontWeight: 700, fontSize: '0.9rem',
                  border: step === s ? '2px solid var(--gold)' : 'none',
                  flexShrink: 0, zIndex: 1,
                  boxShadow: step === s ? '0 0 16px rgba(212,175,55,0.4)' : 'none',
                  transition: 'all 0.3s',
                }}>{s}</div>
                <div style={{ fontSize: '0.75rem', color: step >= s ? 'var(--gold)' : 'var(--cream-dim)', marginLeft: '0.5rem', whiteSpace: 'nowrap', display: 'none' }}>
                  {['Your Details', 'Amount', 'Confirm'][i]}
                </div>
                {i < 2 && <div style={{ flex: 1, height: 2, background: step > s ? 'var(--gold)' : 'rgba(255,255,255,0.08)', margin: '0 0.75rem' }} />}
              </div>
            ))}
          </div>

          <div className="glass" style={{ padding: 'clamp(1.5rem, 4vw, 2.5rem)', borderRadius: '24px' }}>

            {/* ── Step 1: Personal Info ─────────────────────────────────────── */}
            {step === 1 && (
              <div>
                <h2 style={{ fontFamily: 'var(--font-display)', fontSize: '1.75rem', fontWeight: 700, marginBottom: '1.75rem' }}>Your Details</h2>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '1.25rem' }}>
                  <div>
                    <label style={{ fontSize: '0.8rem', color: 'var(--cream-dim)', letterSpacing: '0.05em', display: 'block', marginBottom: '0.4rem' }}>Full Name *</label>
                    <input id="donor-name" className="input-field" type="text" placeholder="Enter your full name" value={form.donorName} onChange={e => setField('donorName', e.target.value)} required />
                  </div>
                  <div>
                    <label style={{ fontSize: '0.8rem', color: 'var(--cream-dim)', letterSpacing: '0.05em', display: 'block', marginBottom: '0.4rem' }}>Email Address *</label>
                    <input id="donor-email" className="input-field" type="email" placeholder="your@email.com" value={form.email} onChange={e => setField('email', e.target.value)} required />
                    <p style={{ fontSize: '0.75rem', color: 'var(--cream-dim)', marginTop: '0.3rem', opacity: 0.7 }}>Receipt will be sent to this email.</p>
                  </div>
                  <div>
                    <label style={{ fontSize: '0.8rem', color: 'var(--cream-dim)', letterSpacing: '0.05em', display: 'block', marginBottom: '0.4rem' }}>Phone Number *</label>
                    <input id="donor-phone" className="input-field" type="tel" placeholder="+91 9876543210" value={form.phone} onChange={e => setField('phone', e.target.value)} required />
                  </div>
                </div>
                {error && <p style={{ fontSize: '0.85rem', color: '#f87171', marginTop: '1rem' }}>{error}</p>}
                <button id="next-step-1" className="btn btn-gold" onClick={goToStep2} style={{ marginTop: '2rem', width: '100%' }}>
                  Continue to Amount →
                </button>
              </div>
            )}

            {/* ── Step 2: Amount & Payment ──────────────────────────────────── */}
            {step === 2 && (
              <div>
                <h2 style={{ fontFamily: 'var(--font-display)', fontSize: '1.75rem', fontWeight: 700, marginBottom: '1.75rem' }}>Amount &amp; Payment</h2>

                {/* Preset amounts */}
                <div style={{ marginBottom: '1.5rem' }}>
                  <label style={{ fontSize: '0.8rem', color: 'var(--cream-dim)', letterSpacing: '0.05em', display: 'block', marginBottom: '0.8rem' }}>Select Amount (₹)</label>
                  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '0.75rem' }}>
                    {presetAmounts.map(amt => (
                      <button key={amt} id={`amount-${amt}`}
                        onClick={() => { setField('amount', amt); setField('customAmount', ''); }}
                        style={{
                          padding: '0.85rem', borderRadius: '12px', border: '1.5px solid',
                          borderColor: form.amount === amt && !form.customAmount ? 'var(--gold)' : 'rgba(255,255,255,0.08)',
                          background: form.amount === amt && !form.customAmount ? 'rgba(212,175,55,0.12)' : 'rgba(255,255,255,0.03)',
                          color: form.amount === amt && !form.customAmount ? 'var(--gold)' : 'var(--cream)',
                          cursor: 'pointer', fontWeight: 600, fontSize: '1rem',
                          fontFamily: 'var(--font-display)', transition: 'all 0.2s',
                        }}>
                        ₹{amt.toLocaleString('en-IN')}
                      </button>
                    ))}
                  </div>
                </div>

                {/* Custom amount */}
                <div style={{ marginBottom: '1.5rem' }}>
                  <label style={{ fontSize: '0.8rem', color: 'var(--cream-dim)', letterSpacing: '0.05em', display: 'block', marginBottom: '0.4rem' }}>Or Enter Custom Amount (₹)</label>
                  <input id="custom-amount" className="input-field" type="number" min="1" placeholder="e.g. 2500" value={form.customAmount} onChange={e => { setField('customAmount', e.target.value); setField('amount', 0); }} />
                </div>

                {/* Payment Method */}
                <div style={{ marginBottom: '1.5rem' }}>
                  <label style={{ fontSize: '0.8rem', color: 'var(--cream-dim)', letterSpacing: '0.05em', display: 'block', marginBottom: '0.8rem' }}>Payment Method</label>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '0.6rem' }}>
                    {paymentMethods.map(pm => (
                      <label key={pm.id} htmlFor={`pm-${pm.id}`}
                        style={{ display: 'flex', alignItems: 'center', gap: '1rem', padding: '0.9rem 1.25rem', borderRadius: '12px', border: '1.5px solid', borderColor: form.paymentMethod === pm.id ? 'var(--gold)' : 'rgba(255,255,255,0.08)', background: form.paymentMethod === pm.id ? 'rgba(212,175,55,0.08)' : 'rgba(255,255,255,0.02)', cursor: 'pointer', transition: 'all 0.2s' }}>
                        <input id={`pm-${pm.id}`} type="radio" name="paymentMethod" value={pm.id} checked={form.paymentMethod === pm.id} onChange={() => setField('paymentMethod', pm.id)} style={{ accentColor: 'var(--gold)' }} />
                        <span style={{ fontSize: '1.1rem' }}>{pm.icon}</span>
                        <span style={{ fontSize: '0.9rem', color: 'var(--cream)' }}>{pm.label}</span>
                      </label>
                    ))}
                  </div>
                </div>

                <div>
                  <label style={{ fontSize: '0.8rem', color: 'var(--cream-dim)', letterSpacing: '0.05em', display: 'block', marginBottom: '0.4rem' }}>Notes (Optional)</label>
                  <textarea id="donation-notes" className="input-field" rows={2} placeholder="Purpose of donation..." value={form.notes} onChange={e => setField('notes', e.target.value)} style={{ resize: 'none' }} />
                </div>

                {error && <p style={{ fontSize: '0.85rem', color: '#f87171', marginTop: '1rem' }}>{error}</p>}

                <div style={{ display: 'flex', gap: '1rem', marginTop: '2rem' }}>
                  <button className="btn btn-glass" onClick={() => setStep(1)} style={{ flex: 1 }}>← Back</button>
                  <button id="next-step-2" className="btn btn-gold" onClick={() => { if (!finalAmount || finalAmount < 1) { setError('Enter a valid amount.'); return; } setError(''); setStep(3); }} style={{ flex: 2 }}>Review Donation →</button>
                </div>
              </div>
            )}

            {/* ── Step 3: Confirm ───────────────────────────────────────────── */}
            {step === 3 && (
              <div>
                <h2 style={{ fontFamily: 'var(--font-display)', fontSize: '1.75rem', fontWeight: 700, marginBottom: '1.75rem' }}>Confirm Donation</h2>

                {/* Summary */}
                <div className="glass-gold" style={{ padding: '1.75rem', borderRadius: '16px', marginBottom: '2rem' }}>
                  <div style={{ textAlign: 'center', marginBottom: '1.5rem' }}>
                    <div style={{ fontSize: '0.75rem', letterSpacing: '0.12em', textTransform: 'uppercase', color: 'var(--gold)', marginBottom: '0.4rem' }}>Donation Amount</div>
                    <div style={{ fontFamily: 'var(--font-display)', fontSize: '3rem', fontWeight: 700, color: 'var(--gold)' }}>₹{finalAmount.toLocaleString('en-IN')}</div>
                  </div>
                  {[
                    { label: 'Donor Name', value: form.donorName },
                    { label: 'Email', value: form.email },
                    { label: 'Phone', value: form.phone },
                    { label: 'Payment Method', value: paymentMethods.find(p => p.id === form.paymentMethod)?.label || form.paymentMethod },
                    ...(form.notes ? [{ label: 'Notes', value: form.notes }] : []),
                  ].map(r => (
                    <div key={r.label} style={{ display: 'flex', justifyContent: 'space-between', padding: '0.6rem 0', borderBottom: '1px solid rgba(212,175,55,0.1)', fontSize: '0.88rem' }}>
                      <span style={{ color: 'var(--cream-dim)' }}>{r.label}</span>
                      <span style={{ color: 'var(--cream)', fontWeight: 500, textAlign: 'right', maxWidth: '60%' }}>{r.value}</span>
                    </div>
                  ))}
                </div>

                <div className="glass" style={{ padding: '1rem 1.25rem', borderRadius: '10px', marginBottom: '1.5rem', fontSize: '0.8rem', color: 'var(--cream-dim)', lineHeight: 1.6 }}>
                  🔒 Your payment is secured. A receipt (ID: GOC-{new Date().getFullYear()}-XXXX) will be emailed to <strong style={{ color: 'var(--cream)' }}>{form.email}</strong>.
                </div>

                {process.env.NEXT_PUBLIC_PAYMENT_MODE === 'mock' && (
                  <div style={{ padding: '0.75rem 1.25rem', borderRadius: '10px', background: 'rgba(251,191,36,0.08)', border: '1px solid rgba(251,191,36,0.25)', color: '#fbbf24', fontSize: '0.8rem', marginBottom: '1.5rem' }}>
                    🧪 <strong>Dev Mode:</strong> Mock payment active — no real money charged.
                  </div>
                )}

                {error && <p style={{ fontSize: '0.85rem', color: '#f87171', marginBottom: '1rem' }}>{error}</p>}

                <div style={{ display: 'flex', gap: '1rem' }}>
                  <button className="btn btn-glass" onClick={() => setStep(2)} disabled={loading} style={{ flex: 1 }}>← Back</button>
                  <button id="confirm-donation" className="btn btn-gold" onClick={handleDonate} disabled={loading} style={{ flex: 2 }}>
                    {loading ? '⏳ Processing...' : `🙏 Donate ₹${finalAmount.toLocaleString('en-IN')}`}
                  </button>
                </div>
              </div>
            )}
          </div>

          {/* Trust badges */}
          <div style={{ display: 'flex', justifyContent: 'center', gap: '2rem', flexWrap: 'wrap', marginTop: '2rem' }}>
            {['🔒 Secure Payment', '📧 Email Receipt', '✝ Kingdom Impact'].map(b => (
              <span key={b} style={{ fontSize: '0.8rem', color: 'var(--cream-dim)' }}>{b}</span>
            ))}
          </div>
        </div>
      </section>

      <Footer />
    </>
  );
}

'use client';
import { useEffect, useState } from 'react';
import Navbar from '@/components/Navbar';
import Footer from '@/components/Footer';

interface Event {
  id: string;
  title: string;
  description: string;
  date: string;
  time: string;
  location: string;
  isPublished: boolean;
}

const categoryColors: Record<string, string> = {
  Worship: '#7B5EA7',
  Special: '#D4AF37',
  Youth: '#22c55e',
  "Women's": '#C9848A',
  Outreach: '#3B82F6',
};

export default function EventsPage() {
  const [events, setEvents] = useState<Event[]>([]);
  const [loading, setLoading] = useState(true);

  const API = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000/api';

  useEffect(() => {
    const fetchEvents = async () => {
      try {
        const res = await fetch(`${API}/events?upcoming=true&limit=20`);
        const data = await res.json();
        setEvents(data.events || []);
      } catch (err) {
        console.error('Failed to fetch events', err);
      } finally {
        setLoading(false);
      }
    };
    fetchEvents();
  }, [API]);

  return (
    <>
      <Navbar />

      {/* Header */}
      <section className="gradient-hero" style={{ paddingTop: '140px', paddingBottom: '5rem', textAlign: 'center' }}>
        <div className="container">
          <div className="section-label" style={{ justifyContent: 'center' }}>Stay Connected</div>
          <h1 style={{ fontFamily: 'var(--font-display)', fontSize: 'clamp(2.5rem, 5vw, 4rem)', fontWeight: 700, marginBottom: '1rem' }}>
            Upcoming <span className="text-gradient-gold">Events</span>
          </h1>
          <p style={{ color: 'var(--cream-dim)', maxWidth: '540px', margin: '0 auto', lineHeight: 1.8 }}>
            Join us for worship services, special celebrations, and community gatherings. All are welcome.
          </p>
        </div>
      </section>

      {/* Events Grid */}
      <section className="section" style={{ background: 'var(--midnight)', minHeight: '50vh' }}>
        <div className="container">
          {loading ? (
            <div style={{ textAlign: 'center', padding: '5rem', color: 'var(--cream-dim)' }}>Loading events...</div>
          ) : events.length > 0 ? (
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: '1.75rem', paddingBottom: '3rem' }}>
              {events.map(ev => {
                const isUpcoming = new Date(ev.date) >= new Date();
                const accentColor = 'var(--gold)';
                return (
                  <article key={ev.id} className="glass card-hover" style={{ borderRadius: '20px', overflow: 'hidden' }}>
                    <div style={{ height: '4px', background: accentColor }} />
